using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker(reorderThreshold: 5);
    }

    #region Constructor

    [TestMethod]
    public void Constructor_DefaultThreshold_IsAccepted()
    {
        var tracker = new InventoryTracker();
        Assert.IsNotNull(tracker);
    }

    [TestMethod]
    public void Constructor_NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => new InventoryTracker(reorderThreshold: -1));
    }

    #endregion

    #region GetStockLevel

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-999"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.GetStockLevel(sku!));
    }

    #endregion

    #region AddStock

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("WIDGET-A", 20);
        Assert.AreEqual(20, _tracker.GetStockLevel("WIDGET-A"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("WIDGET-A", 10);
        _tracker.AddStock("WIDGET-A", 5);
        Assert.AreEqual(15, _tracker.GetStockLevel("WIDGET-A"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void AddStock_NonPositiveQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("WIDGET-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void AddStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock(sku!, 10));
    }

    #endregion

    #region RemoveStock

    [TestMethod]
    public void RemoveStock_SufficientStock_ReducesLevel()
    {
        _tracker.AddStock("BOLT-7", 30);
        _tracker.RemoveStock("BOLT-7", 12);
        Assert.AreEqual(18, _tracker.GetStockLevel("BOLT-7"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_SetsToZero()
    {
        _tracker.AddStock("BOLT-7", 10);
        _tracker.RemoveStock("BOLT-7", 10);
        Assert.AreEqual(0, _tracker.GetStockLevel("BOLT-7"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("BOLT-7", 5);
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("BOLT-7", 10));
    }

    [TestMethod]
    public void RemoveStock_UnknownSku_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("GHOST", 1));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-3)]
    public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
    {
        _tracker.AddStock("BOLT-7", 20);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("BOLT-7", quantity));
    }

    #endregion

    #region NeedsReorder

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.AddStock("GEAR-1", 20);
        Assert.IsFalse(_tracker.NeedsReorder("GEAR-1"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _tracker.AddStock("GEAR-1", 5); // threshold is 5
        Assert.IsTrue(_tracker.NeedsReorder("GEAR-1"));
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.AddStock("GEAR-1", 2);
        Assert.IsTrue(_tracker.NeedsReorder("GEAR-1"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("MISSING"));
    }

    #endregion

    #region TransferTo (Warehouse Transfers)

    [TestMethod]
    public void TransferTo_ValidTransfer_MovesStock()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("PIPE-3", 50);

        _tracker.TransferTo(destination, "PIPE-3", 20);

        Assert.AreEqual(30, _tracker.GetStockLevel("PIPE-3"));
        Assert.AreEqual(20, destination.GetStockLevel("PIPE-3"));
    }

    [TestMethod]
    public void TransferTo_EntireStock_EmptiesSource()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("PIPE-3", 15);

        _tracker.TransferTo(destination, "PIPE-3", 15);

        Assert.AreEqual(0, _tracker.GetStockLevel("PIPE-3"));
        Assert.AreEqual(15, destination.GetStockLevel("PIPE-3"));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_ThrowsAndLeavesUnchanged()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("PIPE-3", 5);
        destination.AddStock("PIPE-3", 10);

        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.TransferTo(destination, "PIPE-3", 20));

        // Both remain unchanged
        Assert.AreEqual(5, _tracker.GetStockLevel("PIPE-3"));
        Assert.AreEqual(10, destination.GetStockLevel("PIPE-3"));
    }

    [TestMethod]
    public void TransferTo_NullDestination_Throws()
    {
        _tracker.AddStock("PIPE-3", 10);
        Assert.ThrowsException<ArgumentNullException>(
            () => _tracker.TransferTo(null!, "PIPE-3", 5));
    }

    [TestMethod]
    public void TransferTo_DestinationAlreadyHasStock_Accumulates()
    {
        var destination = new InventoryTracker();
        destination.AddStock("VALVE-2", 8);
        _tracker.AddStock("VALVE-2", 30);

        _tracker.TransferTo(destination, "VALVE-2", 12);

        Assert.AreEqual(18, _tracker.GetStockLevel("VALVE-2"));
        Assert.AreEqual(20, destination.GetStockLevel("VALVE-2"));
    }

    #endregion
}

